mapper.select:
SELECT CASE WHEN ttm.complete_dt IS NOT NULL THEN '완료' ELSE '진행' END AS name, COUNT(*) AS cnt FROM esg.tb_task_manager_detail ttm WHERE ttm.comp_id = #{compId} AND ttm.req_dt BETWEEN TO_DATE(#{searchText}, 'YYYYMM') AND CURRENT_DATE + interval '1 day'
AND ttm.task_detail_user_id = #{searchText3}
AND ttm.cancel_dt IS NULL AND ttm.use_yn = 'Y' GROUP BY name;

	SELECT
		  task_year,
		  task_month,
		  task_day,
		  task_seq
	 FROM esg.tb_task_manager
	WHERE req_info_key = #{reqInfoKey}
	  AND user_id = #{userId}
      AND comp_id = #{compId}
	  AND task_year = #{taskYear}
	  AND task_month = #{taskMonth}
	  AND task_day = #{taskDay}
    LIMIT 1

select t1.*
from esg.tb_task_manager t1
where 1=1
	and t1.comp_id = #{compId}
	and t1.task_month = #{taskMonth}
	and t1.task_day = #{taskDay}
	and t1.req_info_key = #{reqInfoKey}
	and t1.req_menu_id = #{reqMenuId}
	and t1.cancel_dt is null

select t1.*
from esg.tb_task_manager_detail t1
where 1=1
	and t1.comp_id = #{compId}
	and t1.req_info_key = #{reqInfoKey}
	and t1.req_menu_id = #{reqMenuId}
	and t1.user_id = #{userId}
	and t1.task_detail_div = #{taskDetailDiv}
	and t1.cancel_dt is null

	select t1.*
	from esg.tb_safety_checklist t1
    where 1=1
		and t1.write_year = #{writeYear}
		and t1.comp_id = #{compId}
		and t1.std_eq_id = #{stdEqId}

mapper.update:
update esg.tb_task_manager_detail set
	complete_dt = now(),
	task_detail_div = #{taskDetailDiv}
where comp_id = #{compId}
	and task_year = #{taskYear}
	and task_month = #{taskMonth}
	and task_day = #{taskDay}
	and req_info_key = #{reqInfoKey}
	and task_detail_div = #{chkTaskDetailDiv}

update esg.tb_task_manager_detail set
	cancel_dt = now()
where comp_id = #{compId}
	and req_info_key = #{reqInfoKey}

UPDATE esg.tb_task_manager_detail
SET use_yn = #{useYn}
WHERE req_info_key = #{formattedTargetId}
    AND comp_id = #{compId}

UPDATE esg.tb_task_manager_detail ttmd SET
complete_dt = NOW()
complete_dt =NULL
, task_detail_content = #{taskDetailContent}
FROM esg.tb_approval_info tai, esg.tb_common_d tdcd WHERE ttmd.task_detail_user_id = (SELECT user_id FROM esg.tb_hr_info WHERE hr_id = #{userId}) AND ttmd.comp_id = #{compId} AND ttmd.req_info_key = #{reqInfoKey} AND ttmd.task_detail_div = #{taskDetailDiv} AND ttmd.cancel_dt IS NULL AND tai.target_type = split_part(ttmd.req_info_key, '^&', 1) AND tai.target_id = replace(regexp_replace(ttmd.req_info_key, '^[^&]+\^&', ''), '^&', '') AND tai.param = tdcd.extra_2 AND tdcd.minor_cd = ttmd.task_detail_div AND tdcd.major_cd = 'C0044';

		UPDATE esg.tb_task_manager_detail ttmd
	       SET
			   cancel_dt = NOW(),
			   task_detail_content = #{taskDetailContent}
		  FROM esg.tb_approval_info tai,
               esg.tb_common_d tdcd
		 WHERE ttmd.task_detail_user_id = (SELECT user_id FROM esg.tb_hr_info WHERE hr_id = #{userId})
		   AND ttmd.comp_id = #{compId}
		   AND ttmd.req_info_key = #{reqInfoKey}
		   AND ttmd.task_detail_div = #{taskDetailDiv}
		   AND ttmd.cancel_dt IS NULL
		   AND tai.target_type = split_part(ttmd.req_info_key, '^&', 1)
		   AND tai.target_id = replace(regexp_replace(ttmd.req_info_key, '^[^&]+\^&', ''), '^&', '')
		   AND tai.param = tdcd.extra_2
		   AND tdcd.minor_cd = ttmd.task_detail_div
		   AND tdcd.major_cd = 'C0044';

UPDATE esg.tb_task_manager_detail
SET
	  task_detail_user_chk = #{taskDetailUserChk},
	  task_detail_user_chk_dt = NOW()
WHERE task_detail_user_id = #{userId}
  AND comp_id = #{compId}
  AND task_year = #{taskYear}
  AND task_month = #{taskMonth}
  AND task_day = #{taskDay}
  AND task_seq = #{taskSeq}
  AND task_detail_user_chk_dt IS NULL

