     	    select t1.*
			from esg.tb_safety_inspection_log t1
			where std_eq_id = #{stdEqId}
				and equipment_id = #{equipmentId}
				and check_dt = to_char(now(), 'YYYYMMDD')
			limit 1

     	    select not exists (
			  select 1
			  from esg.tb_safety_inspection_log_detail t1
			  where 1=1
				and t1.write_year = #{writeYear}
				and t1.doc_no = #{docNo}
				and t1.acceptable_yn = 'N'
				and t1.non_compliant_yn = 'N'
			) as result

