DELETE FROM esg.tb_notice_alarm_his
WHERE (CURRENT_DATE - TO_DATE(alarm_dt, 'YYYYMMDD')) >= #{deleteCycle}
  AND read_yn = 'Y'


DELETE FROM esg.tb_emergency_alarm_his
WHERE (CURRENT_DATE - TO_DATE(alarm_dt, 'YYYYMMDD')) >= #{deleteCycle}
  AND read_yn = 'Y'


DELETE FROM esg.tb_training_plan_implementation_alarm_his
WHERE (CURRENT_DATE - TO_DATE(alarm_dt, 'YYYYMMDD')) >= #{deleteCycle}
  AND read_yn = 'Y'
